import * as React from "react"
import { ScrollArea } from "@/components/ui/scroll-area"
import { cn } from "@/lib/utils"

export interface SidebarCourseProps {
  /** Conteudo fixo no topo (ex: ProgressCourse) */
  header?: React.ReactNode
  /** Conteudo scrollavel (accordions, tasks, etc.) */
  children: React.ReactNode
  className?: string
}

function SidebarCourse({ header, children, className }: SidebarCourseProps) {
  return (
    <aside
      data-slot="sidebar-course"
      className={cn("flex flex-col w-full max-w-[354px] h-full", className)}
    >
      {header && <div className="shrink-0">{header}</div>}
      <ScrollArea className="flex-1">
        <div className="flex flex-col">{children}</div>
      </ScrollArea>
    </aside>
  )
}

export { SidebarCourse }

"use client"

import * as React from "react"
import { ArrowLeftIcon } from "lucide-react"
import { CycleIcon } from "@/components/icons/CycleIcon"
import { Progress } from "@/components/ui/progress"
import { ProgressStage } from "@/components/ui/progress-stage"
import { cn } from "@/lib/utils"

export interface ProgressCourseProps {
  /** Titulo do curso ou unidade */
  title: string
  /** Callback ao clicar na seta de voltar */
  onBack?: () => void
  /** Mostra/esconde seta de voltar */
  showBack?: boolean
  /** Texto informativo acima do progresso (ex: "No seu ritmo, você conclui em 2 meses") */
  infoText?: string
  /** Texto e href do link ao lado do subtexto */
  link?: { label: string; href: string }
  /** Tipo de barra de progresso */
  progressType?: "bar" | "stage"
  /** Valor do progresso (0-100 para bar, 0-stages para stage) */
  progressValue: number
  /** Total de stages (usado apenas quando progressType="stage") */
  stages?: number
  /** Percentual exibido ao lado da barra */
  percentLabel?: string
  /** Tema de cor aplicado ao progresso (ex: "theme-class") */
  theme?: string
  className?: string
}

function ProgressCourse({
  title,
  onBack,
  showBack = true,
  infoText,
  link,
  progressType = "stage",
  progressValue,
  stages = 10,
  percentLabel,
  theme,
  className,
}: ProgressCourseProps) {
  return (
    <div
      data-slot="progress-course"
      className={cn(
        "flex flex-col gap-3 bg-muted border-b border-border",
        "p-4 md:p-6",
        className
      )}
    >
      {/* Title row */}
      <div className="flex items-center gap-2">
        {showBack && onBack && (
          <button
            type="button"
            onClick={onBack}
            className="shrink-0 text-foreground hover:text-muted-foreground transition-colors"
            aria-label="Voltar"
          >
            <CycleIcon icon={ArrowLeftIcon} size="xs" decorative />
          </button>
        )}
        <h2 className="heading-md md:heading-md text-foreground font-semibold text-base md:text-lg leading-6 md:leading-7 tracking-tight truncate">
          {title}
        </h2>
      </div>

      {/* Info + link */}
      {infoText && (
        <div className="flex flex-col gap-0.5">
          <p className="text-sm md:text-base text-foreground leading-5 md:leading-6">
            {infoText}
          </p>
          <div className="flex items-center gap-2">
            <span className="text-xs text-muted-foreground leading-[18px]">
              Quer avançar mais rápido?
            </span>
            {link && (
              <span className="theme-class">
                <a
                  href={link.href}
                  className="text-xs font-medium underline underline-offset-2 text-primary"
                >
                  {link.label}
                </a>
              </span>
            )}
          </div>
        </div>
      )}

      {/* Progress bar */}
      <div className="flex items-center gap-2 w-full">
        {progressType === "stage" ? (
          <ProgressStage
            stages={stages}
            value={progressValue}
            theme={theme}
            className="flex-1"
          />
        ) : (
          <Progress
            value={progressValue}
            theme={theme}
            className="flex-1"
          />
        )}
        {percentLabel && (
          <span className="text-xs text-muted-foreground leading-[18px] shrink-0">
            {percentLabel}
          </span>
        )}
      </div>
    </div>
  )
}

export { ProgressCourse }

"use client"

import * as React from "react"
import type { LucideIcon } from "lucide-react"
import { CycleIcon } from "@/components/icons/CycleIcon"
import { Badge } from "@/components/ui/badge"
import { Checkbox } from "@/components/ui/checkbox"
import { cn } from "@/lib/utils"

export interface TaskCourseProps {
  /** Activity title */
  title: string
  /** Icon to display (Lucide component) */
  icon: LucideIcon
  /** Activity type label shown in badge (e.g. "Vídeo", "Quiz") */
  typeLabel: string
  /** Duration or meta text (e.g. "12 min") */
  duration?: string
  /** Whether this task is the currently active one */
  active?: boolean
  /** Whether this task is completed (controls checkbox state) */
  completed?: boolean
  /** Callback when checkbox changes */
  onCompletedChange?: (checked: boolean) => void
  /** Callback when task row is clicked */
  onClick?: () => void
  className?: string
}

function TaskCourse({
  title,
  icon,
  typeLabel,
  duration,
  active = false,
  completed = false,
  onCompletedChange,
  onClick,
  className,
}: TaskCourseProps) {
  return (
    <div
      data-slot="task-course"
      data-active={active || undefined}
      data-completed={completed || undefined}
      role="button"
      tabIndex={0}
      onClick={onClick}
      onKeyDown={(e) => {
        if (e.key === "Enter" || e.key === " ") {
          e.preventDefault()
          onClick?.()
        }
      }}
      className={cn(
        "relative flex items-start gap-3 cursor-pointer outline-none transition-colors",
        "py-2 md:py-4 pr-4 md:pr-6",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50",
        active
          ? "theme-class bg-background hover:bg-muted/50 pl-[calc(4px+theme(spacing.4))] md:pl-[calc(4px+theme(spacing.6))]"
          : "bg-background hover:bg-muted/50 pl-4 md:pl-6",
        className
      )}
    >
      {/* Active indicator bar */}
      {active && (
        <div className="absolute left-0 top-0 bottom-0 w-1 bg-primary rounded-r-sm" />
      )}

      {/* Icon */}
      <div className="shrink-0 mt-0.5 text-muted-foreground">
        <CycleIcon icon={icon} size="xs" decorative />
      </div>

      {/* Content */}
      <div className="flex-1 min-w-0">
        <span className="text-sm leading-5 text-foreground line-clamp-2">
          {title}
        </span>
        <div className="flex items-center gap-1.5 mt-0.5">
          <Badge variant={active ? "default" : "muted"} size="sm">
            {typeLabel}
          </Badge>
          {duration && (
            <>
              <span className="text-muted-foreground text-xs">•</span>
              <span className="text-muted-foreground text-xs">{duration}</span>
            </>
          )}
        </div>
      </div>

      {/* Checkbox */}
      <div className="shrink-0 mt-1" onClick={(e) => e.stopPropagation()}>
        <Checkbox
          variant="circular"
          size="lg"
          checked={completed}
          onCheckedChange={(checked) => onCompletedChange?.(checked === true)}
          theme={completed ? "theme-positive" : undefined}
        />
      </div>
    </div>
  )
}

export { TaskCourse }

